CREATE TYPE "UserRole" AS ENUM ('ADMIN','PREMIUM_USER','FREE_USER');
CREATE TYPE "SessionStatus" AS ENUM ('ACTIVE','REVOKED','EXPIRED');
CREATE TABLE "users" ("id" TEXT PRIMARY KEY, "email" TEXT NOT NULL UNIQUE, "passwordHash" TEXT NOT NULL, "name" TEXT, "avatarUrl" TEXT, "emailVerifiedAt" TIMESTAMP(3), "isActive" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "roles" ("id" TEXT PRIMARY KEY, "name" "UserRole" NOT NULL UNIQUE);
CREATE TABLE "_RoleToUser" ("A" TEXT NOT NULL REFERENCES "roles"("id") ON DELETE CASCADE ON UPDATE CASCADE, "B" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX "_RoleToUser_AB_unique" ON "_RoleToUser"("A", "B");
CREATE INDEX "_RoleToUser_B_index" ON "_RoleToUser"("B");
CREATE TABLE "sessions" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE, "status" "SessionStatus" NOT NULL DEFAULT 'ACTIVE', "ipAddress" TEXT, "userAgent" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "expiresAt" TIMESTAMP(3) NOT NULL, "revokedAt" TIMESTAMP(3));
CREATE TABLE "refresh_tokens" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE, "sessionId" TEXT NOT NULL REFERENCES "sessions"("id") ON DELETE CASCADE ON UPDATE CASCADE, "tokenHash" TEXT NOT NULL UNIQUE, "family" TEXT NOT NULL, "replacedById" TEXT, "revokedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "expiresAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "email_verifications" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE, "tokenHash" TEXT NOT NULL UNIQUE, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "expiresAt" TIMESTAMP(3) NOT NULL, "verifiedAt" TIMESTAMP(3));
CREATE TABLE "password_resets" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE, "tokenHash" TEXT NOT NULL UNIQUE, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "expiresAt" TIMESTAMP(3) NOT NULL, "usedAt" TIMESTAMP(3));
CREATE TABLE "login_history" ("id" TEXT PRIMARY KEY, "userId" TEXT REFERENCES "users"("id") ON DELETE SET NULL ON UPDATE CASCADE, "email" TEXT NOT NULL, "ipAddress" TEXT, "userAgent" TEXT, "success" BOOLEAN NOT NULL, "reason" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
INSERT INTO "roles" ("id", "name") VALUES ('role_admin','ADMIN'), ('role_premium','PREMIUM_USER'), ('role_free','FREE_USER') ON CONFLICT DO NOTHING;
